var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"나래 양의 데이터만이라면 지금이라도 조정할 수 있을 걸세.","JPN":"ナルミ君のデータだけだったら、今からでも調整できるはずだ。","ENG":"It's not too late for us to change Narae's data.","TWN":"如果只是娜拉的資料，現在應該還能調整。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ADMIN_COFFIN_NULL_QM","text":{"KOREA":"신경 쓰인다면 바로 조치해 두지.","JPN":"気になるならすぐに変えるが。","ENG":"Let me know if it bothers you. I will make changes right away.","TWN":"你要是介意的話，我現在就能換成別的。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"괜찮아. 넣자고 한 건 나잖아.","JPN":"大丈夫。入れようと言ったのは私だし。","ENG":"It's all right. I'm the one who suggested it.","TWN":"沒關係，是我說要放進去的。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"나이트와 비숍은 서로 정반대였어. 직접 겪어 보면 세 사람에게도 도움이 될 거야.","JPN":"ナイトとビショップは正反対だった。みんなも直接経験してみれば役に立つはずだよ。","ENG":"Knight and Bishop were polar opposites. It'll be useful for them to go through it.","TWN":"騎士和大主教的戰鬥風格正好相反。都體驗一遍的話，對她們三個也有幫助。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"쳇, 아깝네. 조금만 더 빨리 반응했어도 반격 성공이었는데.","JPN":"チッ、もったいないな。もうちょっと早く反応してたら反撃成功だったのに。","ENG":"Tsk, such a close call. We would have succeeded in attacking back if we'd been faster.","TWN":"嘖，真可惜。反應速度再快一點的話，就可以反擊成功了。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아뇨. 방패는 이미 한계였어요. 이번 같은 방식으로는 어려울 것 같아요.","JPN":"いいえ。盾はすでに限界だったわ。今回みたいなやり方では難しいと思う。","ENG":"No, the shield was at its limit. I don't think this method will work a second time.","TWN":"不行，盾牌已經到達極限，這個戰術似乎行不通。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으으, 그럼 반격을 해도 위험했겠네요.","JPN":"うう、それじゃあ反撃しても危険だったかもしれませんね。","ENG":"Nngh, that means it would've been dangerous to hit back.","TWN":"呃呃，那個反擊也很危險。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"다시 한 번 도전해 봐요. 이번에는 더 잘할 수 있을 거예요.","JPN":"もう一度挑戦してみましょう。次はもっとうまくやれるはずです。","ENG":"Let's try again. We'll do better this time.","TWN":"再挑戰一次吧。這次我們一定能做得更好。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"응? 왜 그러세요?","JPN":"うん？　どうしましたか？","ENG":"Hm? What's wrong?","TWN":"嗯？怎麼了？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저기…… 나한테 화 안 났어?","JPN":"あの……私に怒ってないの？","ENG":"You, um... Aren't you angry at me?","TWN":"那個……你不生我的氣嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네? 제가 펠리세트한테요?","JPN":"はい？　私がフェリセットにですか？","ENG":"Huh? Me? Angry at you?","TWN":"嗯？我生你的氣？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……사과하려고, 했는데. 너랑. 스키너한테.","JPN":"……謝ろうと、思ったのに。あなたと。スキナーに。","ENG":"...I wanted to apologize. To you and Skinner.","TWN":"……我想跟你，還有史金納道歉。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으음, 물론 화내고 물건을 던질 때는 무섭긴 하지만…","JPN":"うーん、もちろん怒ったり物を投げたりする時は怖いですけど……","ENG":"Mmm, I will admit, you are pretty intimidating when you throw things and yell...","TWN":"嗯嗯，你發脾氣摔東西的時候我是有點害怕……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이해해요. 최선을 다해도 잘 안 풀리니까 답답한 거잖아요.","JPN":"理解します。頑張っても上手く行かないから、もどかしいんでしょう？","ENG":"But I understand. You're frustrated because things aren't working out, even when you're trying your best.","TWN":"不過我明白你的心情，拼盡全力卻還是一無所獲，所以很煩躁是吧。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저도 그런 적 많거든요.","JPN":"私もそんな時がたくさんありましたから。","ENG":"I've been in the same situation many times.","TWN":"我也經常那樣。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"노엘도? 항상 웃고 다니는 거 아니었어?","JPN":"ノエルも？　いつも笑ってるんじゃなかったの？","ENG":"You too? I thought you would be smiley-smiley all the time.","TWN":"洛艾兒也是？你不是整天笑呵呵的嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"설마요. 답답할 때가 얼마나 많은데요.","JPN":"まさか。もどかしい時がいっぱいありますよ？","ENG":"Of course not. I get frustrated so often!","TWN":"怎麼可能，我很常煩躁好嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"노래를 부르는데 음이 더 안 올라간다거나, 요리가 기대했던 맛이랑 전혀 다르다거나….","JPN":"歌うときにもっと高い音が出せなかったり、料理が期待してた味と全然違ったり……","ENG":"For instance, when I'm singing and I can't hit the high note, or when I cook and it doesn't taste like what I expected it to be...","TWN":"唱歌時高音唱不上去，做的菜和預期的味道完全相反什麼的……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"노엘은…. 그럴 때 어떻게 하는데?","JPN":"ノエルは……そんな時どうするの？","ENG":"...What do you do then, Noelle?","TWN":"洛艾兒……這種時候你都會怎麼做呢？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"다음엔 더 잘해야지, 라고 마음 먹는 거예요.","JPN":"次はもっとうまくやろうって、心を決めますね。","ENG":"I simply think to myself, \\"I'll try harder next time.\\"","TWN":"我會下定決心，下次要做得更好。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"새로운 도전에 집중하면 실패는 금방 잊어 버리거든요.","JPN":"新しい挑戦に集中してると、失敗はすぐ忘れちゃいますから。","ENG":"Focusing on new challenges helps me forget about failure.","TWN":"專注於新的挑戰，很快就會忘記之前的失敗。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……그런 건 별로 신경 안 쓰는 줄 알았어. 항상 웃고 다녀서.","JPN":"……そんなこと、別に気にしてないと思ったわ。いつも笑ってるから。","ENG":"...I didn't think you really cared about losing, seeing how you're always smiling.","TWN":"……我看你總是笑呵呵的樣子，以為你不太在意那些呢。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"헤헷, 전 약골이라서요.","JPN":"へへっ、私は弱虫なんで。","ENG":"He he, I'm weak as a kitten.","TWN":"嘿嘿，因為我比較弱嘛。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"힘들 때나 슬플 때나 웃을 수 있을 만큼 씩씩하진 않아요.","JPN":"辛い時も悲しい時も、ずっと笑っていられるほど元気じゃないです。","ENG":"I'm not strong enough to always be smiling, regardless of my state.","TWN":"我沒有堅強到無論辛苦或是難過都還能強顏歡笑。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"시뮬레이션 성능은 만족스럽나?","JPN":"シミュレーションの性能には満足がいったかな？","ENG":"Are you satisfied with the simulation quality?","TWN":"對模擬器的性能還滿意嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"네!","JPN":"はい！","ENG":"Yes!","TWN":"很棒！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……흠, 흠. 성능이 좋네요. 어디서 구한 거예요?","JPN":"……ゴホン。素晴らしい性能でした。どこで手に入れたんですか？","ENG":"...Ahem. I guess it's okay. Where did you get it from?","TWN":"……咳咳，性能很棒，是從哪弄來的？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"너희가 부순 로봇들의 부품으로 만들어 주신 거야.","JPN":"あなたたちが壊したロボットの部品で作ってくださったのよ。","ENG":"He made them with all the parts from the robots you destroyed.","TWN":"用你們打爛的機器人零件做的。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"직접 만들었다고요? 이걸?","JPN":"作ったんですか？　これを？","ENG":"You made this yourself? This?","TWN":"老闆親手做的？這個？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그렇다니까. 나야 옆에서 소프트웨어 좀 수정한 정도고.","JPN":"そうなのよ。私は隣でソフトウェアをちょっとだけ修正しただけ。","ENG":"It's true, I'm telling you. All I did was to tweak the software a little.","TWN":"沒錯，我只有在旁邊稍微改一下軟體。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"어째서…….","JPN":"どうして……","ENG":"But why...?","TWN":"為什麼……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L47_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그냥 여기서 지내는 동안 써먹을 사람이 필요한 거 아니었나요?","JPN":"ただここで過ごす間、こき使える人が必要なだけじゃなかったんですか？","ENG":"I thought all you needed was someone to boss around during your stay.","TWN":"你不是只有停留在這裡的這段時間需要人手嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"대체 왜 이렇게까지 해 주는 거예요? 저를 결승에 진출시키면 뭐가 좋은데요?","JPN":"どうしてここまでしてくれるんですか？　私が決勝に進出したら何かいいことでもあるんですか？","ENG":"Why do you care so much? What do you get out of it if I make it to the finals?","TWN":"為什麼要為我們做這麼多？我們打入決賽對你有什麼好處？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"내 꿈이 우주 평화이기 때문이라네.","JPN":"私の夢は宇宙の平和だからな。","ENG":"It's because my dream is to achieve world peace.","TWN":"哈哈，因為我的夢想是宇宙和平。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"꿈이 너무 커서 보이는 문제부터 해결하고 있지.","JPN":"夢が大きすぎて目に見える問題から解決しているんだ。","ENG":"It is a dream so big that I have to start out with the issues in front of me.","TWN":"但這個夢想太過遠大，所以還是先先著手解決眼前的問題吧。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니 말해 보게. 왜 결승에 진출하려는지.","JPN":"だから、話したまえ。どうして決勝に進出しようとしているのか。","ENG":"So tell me. Why do you want to make it to the finals?","TWN":"所以你說說看，你為什麼想打入決賽？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"말하지 않으면?","JPN":"嫌だと言ったら？","ENG":"What if I don't tell you?","TWN":"不說的話會怎樣？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"시뮬레이터에 이용료가 붙을 거야. 분당 할증 5%로.","JPN":"シミュレーターに利用料金がつくわよ。一分ごとに、割増5％で。","ENG":"We'll charge you for the simulator. With five percent interest per minute.","TWN":"收取模擬器使用費，每分鐘加價5%。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"참고로 소급 적용이래.","JPN":"ちなみに、遡及適用だって。","ENG":"It'll be applied retroactively, by the way.","TWN":"喔，還要算上之前的。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"하나부터 열까지 다 토해내. 꼬맹아. 제 값 다 냈다간 우린 평생 무급으로 일해야 돼.","JPN":"一から十まで全部吐き出せ。おこちゃま。全額払うようになったら一生タダ働きする羽目になる。","ENG":"Spill the beans, Kid. If we pay for that, we're gonna be working for free till the day we die.","TWN":"你就一五一十地全都說出來吧，小鬼。如果按原價付錢，我們大概一輩子都要當免費勞工咧。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……본선 결승에서 만나고 싶은 사람이 있어요. 그것뿐이에요.","JPN":"……本戦の決勝で会いたい人がいるんです。ただそれだけです。","ENG":"...There's someone I want to meet at the finals. That's it.","TWN":"……決賽中有我想見的人，僅此而已。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"만나고 싶은 사람?","JPN":"会いたい人？","ENG":"Someone you want to meet?","TWN":"你想見的人？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"한 사람을 만나러 가기 위해 온갖 난관을 돌파하겠다는 결심…! 왠지 낭만적이네요!","JPN":"たった一人に会いに行くために、あらゆる難関を突破してやるという決心……！　何だかロマンチックです！","ENG":"You're determined to go through all of this, just for one person...! How romantic!","TWN":"哇！為了見一個人而克服重重難關的決心……！感覺好浪漫喔！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"꼭 제가 펜릴 소대에 들어오려고 3종 침식체를 잡으러 갈 때 같아요.","JPN":"まるで、私がフェンリル小隊に入るために第3種侵食体をやっつけに行った時みたいです。","ENG":"It's like when I went to hunt down the Category 3 C.O. to get into Fenrir Squad!","TWN":"很像我那時候為了要加入芬里爾小隊，而去抓3類侵蝕體呢。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그거랑은 전혀 다른 것 같은데…….","JPN":"それとは全然違うと思うけど……","ENG":"I feel like those are two very different situations...","TWN":"跟你那個好像完全不一樣……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"좋아. 그럼 앞으로 날 코치라고 부르게.","JPN":"よし。それでは、これからは私のことをコーチと呼びたまえ。","ENG":"All right. From now on, you will call me Coach.","TWN":"很好，那從現在開始，請稱呼我為教練。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"코치요……?","JPN":"コーチですか……？","ENG":"Coach...?","TWN":"教練……？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어……. 부자 양반들 취향이 별나다는 건 알고 있었는데, 이건 나도 처음 듣는걸.","JPN":"えっ……お金持ちの趣味は変わってるってのは知ってたけど、こんなの初めて聞くな。","ENG":"Uh... I've heard of rich people having weird kinks, but this is new.","TWN":"呃……我知道有錢人的嗜好很特別，不過這種情況我也是第一次遇到呢。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"본선 결승까지 보내려면 지시를 내려야 하지 않겠나?","JPN":"本戦の決勝まで送るためには指示を出さないといけないだろう？","ENG":"You'll need instructions to make it to the finals, no?","TWN":"如果想送你們進決賽，我不是得下達指示嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"알겠어요. 코치라고 불러 드릴게요.","JPN":"わかりました。コーチと呼んでもいいです。","ENG":"Fine. I'll call you Coach.","TWN":"好，那我會叫你教練。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"대신에 코치도 저를 펠리세트 양이 아니라 펠리세트라고 불러 주세요.","JPN":"その代わりに、コーチも私のことをフェリセット君じゃなくて、フェリセットって呼んでください。","ENG":"In return, you have to promise me that you'll get me to the finals.","TWN":"不過請教練也把我當自己人，不要太客氣。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그게……. 제 각오니까요.","JPN":"それが……私の覚悟ですから。","ENG":"That's... how determined I am.","TWN":"那是……我的決心。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};